import React from 'react';

const Experience = () => {
  return (
    <section>
      <h2 className="text-2xl font-semibold text-blue-600">Experience</h2>
      <ul className="mt-3 list-disc ml-5 space-y-1">
        <li>2+ years in web development</li>
        <li>Built responsive websites</li>
        <li>Worked with React and Node.js</li>
      </ul>
    </section>
  );
};

export default Experience;
